#!/usr/bin/env bash
set -euo pipefail

THREADS="${1:-60}"
mkdir -p logs-sens3

OMP_NUM_THREADS="${THREADS}" MKL_NUM_THREADS=1 OPENBLAS_NUM_THREADS=1 python -u train_new_structure.py --dataset ICEWS14 --seed 42 --output_root results_new_structure_sens3 --ns_q 6000 --ns_seed 42 --train_predict_ratio 0.3 --batch_size 8192 --max_events_in_single_batch 60000 --source_join_threads "${THREADS}" --dict_mode tag_sum --shared_w dual_msim --ppr_k 100 --top_k_relation 0 --ppr_alpha 0.005 --ppr_beta 0.8 --gamma 0.001 --direct_single_hop 0.85 --decay_direct 0.35 --top_share 100 --top_direct -1 --decay_rel_trans 0.05 --window_semantic_sim 5.0 --window_trans 5.0 > logs-sens3/structure_ICEWS14_alpha0.005_beta0.8_k100.log 2>&1
OMP_NUM_THREADS="${THREADS}" MKL_NUM_THREADS=1 OPENBLAS_NUM_THREADS=1 python -u train_new_structure.py --dataset ICEWS14 --seed 42 --output_root results_new_structure_sens3 --ns_q 6000 --ns_seed 42 --train_predict_ratio 0.3 --batch_size 8192 --max_events_in_single_batch 60000 --source_join_threads "${THREADS}" --dict_mode tag_sum --shared_w dual_msim --ppr_k 100 --top_k_relation 0 --ppr_alpha 0.005 --ppr_beta 0.9 --gamma 0.001 --direct_single_hop 0.85 --decay_direct 0.35 --top_share 100 --top_direct -1 --decay_rel_trans 0.05 --window_semantic_sim 5.0 --window_trans 5.0 > logs-sens3/structure_ICEWS14_alpha0.005_beta0.9_k100.log 2>&1
OMP_NUM_THREADS="${THREADS}" MKL_NUM_THREADS=1 OPENBLAS_NUM_THREADS=1 python -u train_new_structure.py --dataset ICEWS14 --seed 42 --output_root results_new_structure_sens3 --ns_q 6000 --ns_seed 42 --train_predict_ratio 0.3 --batch_size 8192 --max_events_in_single_batch 60000 --source_join_threads "${THREADS}" --dict_mode tag_sum --shared_w dual_msim --ppr_k 100 --top_k_relation 0 --ppr_alpha 0.005 --ppr_beta 0.95 --gamma 0.001 --direct_single_hop 0.85 --decay_direct 0.35 --top_share 100 --top_direct -1 --decay_rel_trans 0.05 --window_semantic_sim 5.0 --window_trans 5.0 > logs-sens3/structure_ICEWS14_alpha0.005_beta0.95_k100.log 2>&1
